package ru.memearena.media.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="media_asset") public class MediaAsset { @Id private UUID id; @Column(name="storage_key",nullable=false,unique=true,length=500) private String storageKey; @Column(name="original_filename",length=255) private String originalFilename; @Column(name="content_type",nullable=false,length=100) private String contentType; @Column(name="size_bytes",nullable=false) private long sizeBytes; @Column(nullable=false,length=64) private String sha256; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) private MediaAssetStatus status; @Column(name="uploaded_by") private UUID uploadedBy; @Column(name="created_at",nullable=false) private Instant createdAt; @Column(name="deleted_at") private Instant deletedAt; protected MediaAsset(){} public MediaAsset(UUID id,String storageKey,String originalFilename,String contentType,long sizeBytes,String sha256,UUID uploadedBy,Instant createdAt){this.id=id;this.storageKey=storageKey;this.originalFilename=originalFilename;this.contentType=contentType;this.sizeBytes=sizeBytes;this.sha256=sha256;this.uploadedBy=uploadedBy;this.createdAt=createdAt;this.status=MediaAssetStatus.ACTIVE;} public UUID getId(){return id;} public String getStorageKey(){return storageKey;} public String getContentType(){return contentType;} public long getSizeBytes(){return sizeBytes;} public String getSha256(){return sha256;} public MediaAssetStatus getStatus(){return status;} public UUID getUploadedBy(){return uploadedBy;} public Instant getCreatedAt(){return createdAt;} public void markOrphaned(){status=MediaAssetStatus.ORPHANED;} public void markDeleted(Instant now){status=MediaAssetStatus.DELETED;deletedAt=now;} }
